function makeAppLinkDecorator(
    type: InjectableConstructor<typeof LinkWithLifecycle>,
    injector: Injector,
): InjectionDecorator {
  const injectorFn = () => Injector.of(type);
  const deregisterFn = type.$$fn.dispose;

  return () => new InjectionDecorator(createDecorator(injectorFn, deregisterFn), type);
